+    /// CONTRACT: AltScreen cleanup must show cursor. It must NOT emit
+    /// cursor restore or scroll region reset (those are inline-only).
+    #[test]
+    fn noninterference_altscreen_cleanup_minimal() {
+        let mut output = Vec::new();
+        {
